import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useCart } from '../context/CartContext';
import { useNavigate } from 'react-router-dom';

function CartDrawer() {
  const { 
    isCartOpen, closeCart, cartItems, 
    updateQuantity, removeFromCart, clearCart, cartTotal 
  } = useCart();
  const navigate = useNavigate();

  const handleCheckout = () => {
    closeCart();
    clearCart();
    navigate('/checkout-success'); // Simulated checkout
  };

  return (
    <AnimatePresence>
      {isCartOpen && (
        <>
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={closeCart}
            style={{
              position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
              background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(3px)',
              zIndex: 9999
            }}
          />
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="cart-drawer glass-card"
            style={{
              position: 'fixed', top: 0, right: 0, bottom: 0,
              width: '100%', maxWidth: '400px', zIndex: 10000,
              display: 'flex', flexDirection: 'column',
              padding: '1.5rem', borderRadius: '15px 0 0 15px',
              borderRight: 'none', borderTop: 'none', borderBottom: 'none'
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
              <h2 style={{ fontSize: '1.5rem', margin: 0 }}>Your Gear Cart</h2>
              <button onClick={closeCart} style={{ background: 'transparent', border: 'none', color: 'var(--text-main)', fontSize: '1.5rem', cursor: 'pointer' }}>
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div style={{ flex: 1, overflowY: 'auto', paddingRight: '10px' }}>
              {cartItems.length === 0 ? (
                <div style={{ textAlign: 'center', color: 'var(--text-muted)', marginTop: '3rem' }}>
                  <i className="fas fa-shopping-cart" style={{ fontSize: '3rem', marginBottom: '1rem', opacity: 0.5 }}></i>
                  <p>Your cart is empty.</p>
                  <button onClick={closeCart} className="btn btn-outline" style={{ marginTop: '1rem' }}>Browse Rentals</button>
                </div>
              ) : (
                cartItems.map((item, index) => (
                  <motion.div 
                    layout
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.9 }}
                    key={`${item.name}-${index}`} 
                    style={{ 
                      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                      background: 'rgba(255,255,255,0.05)', padding: '1rem', 
                      borderRadius: '8px', marginBottom: '1rem',
                      border: '1px solid var(--card-border)'
                    }}
                  >
                    <div style={{ flex: 1 }}>
                      <h4 style={{ margin: '0 0 0.5rem 0', fontSize: '1.1rem' }}>{item.name}</h4>
                      <p style={{ color: 'var(--primary)', fontWeight: 'bold', margin: 0 }}>
                        ₹{item.price.toLocaleString('en-IN')}/day
                      </p>
                    </div>
                    
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '0.5rem' }}>
                      <button onClick={() => removeFromCart(item.name)} style={{ background: 'transparent', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '0.9rem' }}>
                        <i className="fas fa-trash"></i>
                      </button>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(0,0,0,0.2)', padding: '2px 8px', borderRadius: '15px' }}>
                        <button onClick={() => updateQuantity(item.name, item.quantity - 1)} style={{ color: 'var(--text-main)', background: 'transparent', border: 'none', cursor: 'pointer' }}>-</button>
                        <span style={{ fontSize: '0.9rem' }}>{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.name, item.quantity + 1)} style={{ color: 'var(--text-main)', background: 'transparent', border: 'none', cursor: 'pointer' }}>+</button>
                      </div>
                    </div>
                  </motion.div>
                ))
              )}
            </div>

            {cartItems.length > 0 && (
              <div style={{ borderTop: '1px solid var(--card-border)', paddingTop: '1.5rem', marginTop: '1rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem', fontSize: '1.2rem', fontWeight: 'bold' }}>
                  <span>Total Amount:</span>
                  <span className="gradient-text">₹{cartTotal.toLocaleString('en-IN')}</span>
                </div>
                <button className="btn btn-primary" style={{ width: '100%', fontSize: '1.1rem' }} onClick={handleCheckout}>
                  Checkout Securely <i className="fas fa-lock" style={{ marginLeft: '8px' }}></i>
                </button>
              </div>
            )}
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}

export default CartDrawer;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

function Contact() {
  const [loading, setLoading] = useState(false);
  const [successStatus, setSuccessStatus] = useState(false);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);

    /* 
     * INTENDED EMAILJS INTEGRATION:
     * emailjs.sendForm('YOUR_SERVICE_ID', 'YOUR_TEMPLATE_ID', form.current, 'YOUR_PUBLIC_KEY')
     *   .then((result) => setSuccessStatus(true));
     */

    // Simulate API Call for portfolio
    setTimeout(() => {
      setSuccessStatus(true);
      setName('');
      setEmail('');
      setMessage('');
      setLoading(false);
      
      setTimeout(() => setSuccessStatus(false), 5000); // hide success msg after 5s
    }, 1500);
  };

  return (
    <section className="contact section-padding" id="contact">
      <div className="section-header">
        <span className="subtitle">Get in touch</span>
        <h2>Plan Your Trip</h2>
      </div>
      <div className="contact-wrapper">
        <div className="contact-info glass-card">
          <h3>Contact Information</h3>
          <p>Our team will help you plan a thrilling adventure.</p>
        </div>
        <div className="contact-form glass-card">
          <form id="contactForm" onSubmit={handleSubmit}>
            <div className="input-group">
              <input 
                type="text" 
                id="name" 
                required 
                placeholder=" "
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
              <label htmlFor="name">Your Name</label>
            </div>
            <div className="input-group">
              <input 
                type="email" 
                id="email" 
                required 
                placeholder=" "
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
              <label htmlFor="email">Email Address</label>
            </div>
            <div className="input-group">
              <textarea 
                id="message" 
                required 
                placeholder=" " 
                rows="4"
                value={message}
                onChange={(e) => setMessage(e.target.value)}
              ></textarea>
              <label htmlFor="message">Your Message</label>
            </div>
            <AnimatePresence mode="wait">
              {successStatus ? (
                <motion.div 
                  initial={{ opacity: 0, y: 10 }} 
                  animate={{ opacity: 1, y: 0 }} 
                  exit={{ opacity: 0, y: -10 }}
                  style={{ background: 'rgba(45, 212, 191, 0.2)', color: 'var(--accent)', padding: '1rem', borderRadius: '8px', textAlign: 'center', fontWeight: 'bold' }}
                >
                  <i className="fas fa-check-circle" style={{ marginRight: '8px' }}></i> Message sent! We'll be in touch soon.
                </motion.div>
              ) : (
                <motion.button 
                  initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                  type="submit" 
                  className="btn btn-primary btn-block"
                  style={{ opacity: loading ? 0.7 : 1 }}
                  disabled={loading}
                >
                  {loading ? (
                    <>Sending... <i className="fas fa-spinner fa-spin"></i></>
                  ) : (
                    <>Send Message <i className="fas fa-paper-plane"></i></>
                  )}
                </motion.button>
              )}
            </AnimatePresence>
          </form>
        </div>
      </div>
    </section>
  );
}

export default Contact;

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuth } from '../context/AuthContext';

const LoginModal = () => {
  const { isModalOpen, closeLoginModal, loginWithGoogle } = useAuth();
  const [loading, setLoading] = React.useState(false);

  const handleGoogleAuth = async () => {
    setLoading(true);
    await loginWithGoogle();
    setLoading(false);
  };

  return (
    <AnimatePresence>
      {isModalOpen && (
        <>
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={closeLoginModal}
            style={{
              position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
              background: 'rgba(0,0,0,0.7)', backdropFilter: 'blur(5px)',
              zIndex: 9999
            }}
          />
          <motion.div
            initial={{ opacity: 0, scale: 0.95, x: '-50%', y: '-40%' }}
            animate={{ opacity: 1, scale: 1, x: '-50%', y: '-50%' }}
            exit={{ opacity: 0, scale: 0.95, x: '-50%', y: '-40%' }}
            style={{
              position: 'fixed', top: '50%', left: '50%',
              width: '90%', maxWidth: '400px', zIndex: 10000
            }}
            className="glass-card text-center"
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
              <h3 style={{ margin: 0, fontSize: '1.5rem' }}>Sign In to Continue</h3>
              <i className="fas fa-times" style={{ cursor: 'pointer', fontSize: '1.2rem', color: 'var(--text-muted)' }} onClick={closeLoginModal}></i>
            </div>
            
            <p style={{ color: 'var(--text-muted)', marginBottom: '2rem' }}>
              Access your adventure dashboard, manage bookings, and unlock premium gear rentals securely.
            </p>

            <button 
              onClick={handleGoogleAuth}
              disabled={loading}
              style={{
                width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid var(--card-border)',
                background: 'rgba(255,255,255,0.05)', color: 'var(--text-main)', fontSize: '1.1rem',
                cursor: loading ? 'not-allowed' : 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
                transition: 'all 0.3s ease'
              }}
              className="google-btn"
            >
              <i className="fab fa-google" style={{ color: '#ea4335', display: 'flex', alignItems: 'center', marginTop: '2px' }}></i>
              <span style={{ display: 'flex', alignItems: 'center' }}>{loading ? 'Authenticating securely...' : 'Sign in with Google'}</span>
            </button>

            <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginTop: '2rem' }}>
              By continuing, you agree to our Terms of Service and Privacy Policy.
            </p>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

export default LoginModal;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';
import { motion } from 'framer-motion';

function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [menuActive, setMenuActive] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();
  const { user, openLoginModal, logout } = useAuth();
  const { cartCount, toggleCart } = useCart();
  const [dropdownOpen, setDropdownOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 50) {
        setScrolled(true);
      } else {
        setScrolled(false);
      }
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavClick = (e, targetId) => {
    e.preventDefault();
    setMenuActive(false);
    
    if (location.pathname !== '/') {
      navigate('/' + targetId);
      setTimeout(() => {
        if(targetId === '#') {
          window.scrollTo(0, 0);
        } else {
          const target = document.querySelector(targetId);
          if(target) target.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
      }, 100);
      return;
    }

    if (targetId === '#') {
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }
    
    const target = document.querySelector(targetId);
    if (target) {
      target.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  };

  const handleProtectedRouting = (e) => {
    if (!user) {
      e.preventDefault();
      setMenuActive(false);
      openLoginModal();
    } else {
      setMenuActive(false);
    }
  };

  return (
    <header id="header" className={scrolled || location.pathname !== '/' ? 'scrolled' : ''}>
      <nav className="navbar" style={{ position: 'relative' }}>
        <h2 className="logo">
          <Link to="/" onClick={(e) => handleNavClick(e, '#')} style={{color: 'inherit'}}>
            Traveling<span>Tent</span>
          </Link>
        </h2>
        
        <div 
          className="menu-btn" 
          id="menu-btn" 
          onClick={() => setMenuActive(!menuActive)}
        >
          <i className={menuActive ? "fas fa-times" : "fas fa-bars"}></i>
        </div>
        
        <ul className={`all-links ${menuActive ? 'active' : ''}`} id="nav-links" style={{ alignItems: 'center' }}>
          <li><a href="#home" onClick={(e) => handleNavClick(e, '#home')}>Home</a></li>
          <li><a href="#portfolio" onClick={(e) => handleNavClick(e, '#portfolio')}>Destinations</a></li>
          <li><a href="#services" onClick={(e) => handleNavClick(e, '#services')}>Services</a></li>
          <li>
            <Link to="/my-bookings" onClick={handleProtectedRouting} style={{ color: 'var(--primary)', fontWeight: 'bold' }}>
              Dashboard
            </Link>
          </li>
          
          <li style={{ marginLeft: '1rem', position: 'relative' }}>
            <button 
              onClick={toggleCart}
              style={{ background: 'transparent', border: 'none', color: 'var(--text-main)', fontSize: '1.2rem', cursor: 'pointer', padding: '8px' }}
            >
              <i className="fas fa-shopping-cart"></i>
              {cartCount > 0 && (
                <span style={{
                  position: 'absolute', top: 0, right: 0, background: 'var(--accent)', color: 'var(--bg-color)',
                  fontSize: '0.7rem', fontWeight: 'bold', width: '20px', height: '20px',
                  borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center'
                }}>
                  {cartCount}
                </span>
              )}
            </button>
          </li>
          
          <li style={{ marginLeft: '0.5rem' }}>
            {!user ? (
              <button 
                onClick={() => { setMenuActive(false); openLoginModal(); }}
                className="btn btn-primary"
                style={{ cursor: 'pointer', padding: '8px 20px', fontSize: '0.9rem' }}
              >
                Sign In <i className="fas fa-sign-in-alt"></i>
              </button>
            ) : (
              <div style={{ position: 'relative' }}>
                <img 
                  src={user.avatar} 
                  alt={user.name} 
                  onClick={() => setDropdownOpen(!dropdownOpen)}
                  style={{ width: '40px', height: '40px', borderRadius: '50%', cursor: 'pointer', border: '2px solid var(--primary)', objectFit: 'cover' }}
                />
                
                {/* User Dropdown */}
                {dropdownOpen && (
                  <motion.div 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="glass-card"
                    style={{ 
                      position: 'absolute', top: '50px', right: '0', 
                      minWidth: '200px', padding: '1rem', zIndex: 1000 
                    }}
                  >
                    <div style={{ borderBottom: '1px solid var(--card-border)', paddingBottom: '0.5rem', marginBottom: '0.5rem' }}>
                      <p style={{ margin: 0, fontWeight: 'bold' }}>{user.name}</p>
                      <p style={{ margin: 0, fontSize: '0.8rem', color: 'var(--text-muted)' }}>{user.email}</p>
                    </div>
                    <Link to="/my-bookings" onClick={() => setDropdownOpen(false)} style={{ display: 'block', padding: '8px 0', color: 'var(--text-main)', textDecoration: 'none' }}>
                      <i className="fas fa-suitcase-rolling" style={{ width: '20px', color: 'var(--accent)' }}></i> My Trips
                    </Link>
                    <button 
                      onClick={() => { logout(); setDropdownOpen(false); }}
                      style={{ background: 'transparent', border: 'none', color: '#ff4b4b', cursor: 'pointer', padding: '8px 0', textAlign: 'left', width: '100%', fontSize: '1rem', marginTop: '5px' }}
                    >
                      <i className="fas fa-sign-out-alt" style={{ width: '20px' }}></i> Sign Out
                    </button>
                  </motion.div>
                )}
              </div>
            )}
          </li>
        </ul>
      </nav>
    </header>
  );
}

export default Navbar;

